def GlobalExcepthook(exc_type, exc_value, exc_tb):
    if issubclass(exc_type, KeyboardInterrupt):
        sys.__excepthook__(exc_type, exc_value, exc_tb)
        return
    try:
        logger.error(
            'Unhandled exception:\n' + ''.join(
                traceback.format_exception(exc_type, exc_value, exc_tb)
            )
        )
    except Exception:
        pass

def ThreadExcepthook(args):
    if args.exc_type is None:
        return
    try:
        logger.error(
            'Unhandled thread exception:\n' + ''.join(
                traceback.format_exception(args.exc_type, args.exc_value, args.exc_tb)
            )
        )
    except Exception:
        pass

sys.excepthook = GlobalExcepthook
try:
    threading.excepthook = ThreadExcepthook
except AttributeError:
    pass


