def ClassifyFlag(name):
    n = name.lower()
    for s in BoolSuffixes:
        if n.endswith(s):
            return 'bool'
    for s in IntSuffixes:
        if n.endswith(s):
            return 'int'
    for s in StringSuffixes:
        if n.endswith(s):
            return 'string'
    if n.endswith('enabled') or n.endswith('disabled'):
        return 'bool'
    if len(n) > 2 and n[:2] == 'is' and name[2:3].isupper():
        return 'bool'
    if len(n) > 3 and n[:3] == 'has' and name[3:4].isupper():
        return 'bool'
    return 'unknown'

